      pattern: ["interleave","O(1) space","original.next=copy","three phases"],
      algorithm: ["map[old]=new","new.next=map[old.next]","new.random=map[old.random]"],
      tradeoff: ["hashmap simple","interleave O(1)","present hashmap first","clever"],
